  S["status"] extends "succeeded" ? { outcome: "success";   durationMs: number } :
  S["status"] extends "failed"    ? { outcome: "failure";   attempts: number   } :
  S["status"] extends "cancelled" ? { outcome: "cancelled"; reason: string     } :
                                    { outcome: "pending"                        };

